DROP TABLE IF EXISTS `juega`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `juega` (
  `id_partido` int NOT NULL AUTO_INCREMENT,
  `id_equipoUno` int NOT NULL,
  `id_equipoDos` int NOT NULL,
  `golesLocal` int NOT NULL DEFAULT '-1',
  `golesVisitante` int NOT NULL DEFAULT '-1',
  `penalesLocal` int NOT NULL DEFAULT '-1',
  `penalesVisitante` int NOT NULL DEFAULT '-1',
  `id_grupo` int DEFAULT NULL,
  `instancia` varchar(3) DEFAULT NULL,
  `anio` int DEFAULT NULL,
  `torneo` tinyint(1) DEFAULT NULL,
  `dia` datetime DEFAULT NULL,
  `cancha` varchar(6) DEFAULT NULL,
  `orden` int DEFAULT NULL,
  PRIMARY KEY (`id_partido`),
  KEY `id_equipoUno` (`id_equipoUno`),
  KEY `id_equipoDos` (`id_equipoDos`),
  CONSTRAINT `juega_ibfk_1` FOREIGN KEY (`id_equipoUno`) REFERENCES `equipo` (`id`),
  CONSTRAINT `juega_ibfk_2` FOREIGN KEY (`id_equipoDos`) REFERENCES `equipo` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1301 DEFAULT CHARSET=latin1;
